import{_ as t,a}from"./chunks/填写github渠道配置.B-S0-llS.js";import{_ as n,o as i,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"GitHub-Releases-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/github-releases.md","filePath":"de-DE/upload/github-releases.md","lastUpdated":1781962217000}'),d={name:"de-DE/upload/github-releases.md"};function l(o,e,c,u,h,p){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="github-releases-kanal-hinzufugen" tabindex="-1">GitHub-Releases-Kanal hinzufügen <a class="header-anchor" href="#github-releases-kanal-hinzufugen" aria-label="Permalink to &quot;GitHub-Releases-Kanal hinzufügen&quot;">​</a></h1><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><p>Du brauchst nur drei Dinge:</p><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Zweck</th></tr></thead><tbody><tr><td>GitHub-Konto</td><td>Zum Erstellen eines Access Tokens und als Besitzer des Repositories.</td></tr><tr><td>GitHub Access Token</td><td>Damit ImgBed auf die GitHub API zugreifen, Releases erstellen und Dateien hochladen kann.</td></tr><tr><td>Repository-Name</td><td>Du kannst nur den Repository-Namen eintragen, z. B. <code>image</code>.</td></tr></tbody></table><h2 id="einrichtung" tabindex="-1">Einrichtung <a class="header-anchor" href="#einrichtung" aria-label="Permalink to &quot;Einrichtung&quot;">​</a></h2><h3 id="schritt-1-bei-github-anmelden-und-access-token-erstellen" tabindex="-1">Schritt 1: Bei GitHub anmelden und Access Token erstellen <a class="header-anchor" href="#schritt-1-bei-github-anmelden-und-access-token-erstellen" aria-label="Permalink to &quot;Schritt 1: Bei GitHub anmelden und Access Token erstellen&quot;">​</a></h3><ol><li>Melde dich bei GitHub an.</li><li>Klicke oben rechts auf deinen Avatar und öffne <code>Settings</code>.</li><li>Öffne links <code>Developer settings</code>.</li><li>Öffne <code>Personal access tokens</code>.</li><li>Öffne <code>Tokens (classic)</code>.</li><li>Klicke auf <code>Generate new token (classic)</code>.</li><li>Gib dem Token einen gut erkennbaren Namen.</li><li>Wähle eine Laufzeit, die zu deinem Wartungsrhythmus passt.</li><li>Aktiviere die Scopes <code>repo</code> und <code>workflow</code>.</li><li>Kopiere und speichere das Token direkt nach dem Erstellen.</li></ol><p><img src="'+t+'" alt="GitHub-Berechtigungen hinzufügen" loading="lazy"></p><h2 id="schritt-2-github-releases-kanal-in-imgbed-ausfullen" tabindex="-1">Schritt 2: GitHub-Releases-Kanal in ImgBed ausfüllen <a class="header-anchor" href="#schritt-2-github-releases-kanal-in-imgbed-ausfullen" aria-label="Permalink to &quot;Schritt 2: GitHub-Releases-Kanal in ImgBed ausfüllen&quot;">​</a></h2><p>Nachdem du in den Upload-Einstellungen <code>GitHub Releases</code> gewählt hast, fülle diese Felder aus:</p><table tabindex="0"><thead><tr><th>UI-Feld</th><th>Eingabe</th></tr></thead><tbody><tr><td>Kanalname</td><td>Ein frei gewählter Name, z. B. <code>GitHubPrimary</code>.</td></tr><tr><td>Access Token</td><td>Das gerade erstellte GitHub Personal Access Token.</td></tr><tr><td>Repository-Name</td><td>Entweder ein kurzer Name wie <code>image</code> oder ein vollständiger Pfad wie <code>username/image</code>.</td></tr><tr><td>Privates Repository</td><td>Je nach Bedarf ein- oder ausschalten.</td></tr><tr><td>Bemerkung</td><td>Optional, z. B. <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+a+`" alt="GitHub-Kanalkonfiguration ausfüllen" loading="lazy"></p><h2 id="schritt-3-kanal-speichern" tabindex="-1">Schritt 3: Kanal speichern <a class="header-anchor" href="#schritt-3-kanal-speichern" aria-label="Permalink to &quot;Schritt 3: Kanal speichern&quot;">​</a></h2><p>Klicke nach dem Ausfüllen auf Speichern.</p><p>Das System übernimmt dann diese Details:</p><table tabindex="0"><thead><tr><th>Systemverhalten</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Kurzer Repository-Name</td><td>ImgBed erkennt das aktuelle GitHub-Konto und erweitert den Wert zu einem vollständigen Repository-Pfad.</td></tr><tr><td>Vollständiger Repository-Pfad</td><td>ImgBed verwendet <code>username/repository</code> genau so, wie du es eingetragen hast.</td></tr><tr><td>Repository-Prüfung</td><td>Wenn du den Pfad deines aktuellen persönlichen Kontos nutzt, erstellt ImgBed das Repository automatisch, falls es noch nicht existiert. Wenn du manuell einen vollständigen Pfad einträgst, wird dieser direkt verwendet.</td></tr><tr><td>Öffentlich/privat</td><td>Die Repository-Sichtbarkeit wird entsprechend dem aktuellen Schalter synchronisiert.</td></tr></tbody></table><h2 id="kurzcheck" tabindex="-1">Kurzcheck <a class="header-anchor" href="#kurzcheck" aria-label="Permalink to &quot;Kurzcheck&quot;">​</a></h2><p>GitHub Releases funktioniert so:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bei GitHub anmelden</span></span>
<span class="line"><span>-&gt; Access Token erstellen</span></span>
<span class="line"><span>-&gt; Zu ImgBed zurückkehren und Token sowie Repository-Name eintragen</span></span>
<span class="line"><span>-&gt; Speichern</span></span>
<span class="line"><span>-&gt; Wenn nur ein Repo-Name eingetragen ist, ergänzt ImgBed automatisch den aktuellen Benutzernamen</span></span>
<span class="line"><span>-&gt; Wenn username/repo eingetragen ist, nutzt ImgBed den Wert unverändert</span></span>
<span class="line"><span>-&gt; Testbild hochladen</span></span></code></pre></div>`,19)])])}const k=n(d,[["render",l]]);export{m as __pageData,k as default};
